    @staticmethod
    def log2idx_table(value: int) -> int:
        """
        Convert by a function:
            g_idx = round(2**17 * exp(idx * log_k / 2**sigmaPrecision + ln(Smin)))
            
            where log_k = (ln(Smax) - ln(Smin)) / Ns, Smax = 54.82, Smin = 0.11, Ns = 32, sigmaPrecision = 7
        """
        value = torch.clamp(value, 0, len(Log2LinConvertion.table)-1)
        return Log2LinConvertion.table[value.long()].to(value.device)

    @staticmethod
    def idx2log_table(idx: int) -> int:
        """Inverse function to log2idx_table()
        """
        return torch.clamp( torch.searchsorted(Log2LinConvertion.table.to(idx.device), idx), max = len( Log2LinConvertion.table ) - 1 )
    
    @staticmethod
    def difflog2lin(tensor_log_domain: torch.Tensor, sigmaPrecision: int, log_k: float) -> torch.Tensor:
        """Convert difference of logs of sigmas (i.e. ln(s1) - ln(s2)) to linear domain
        """
        return torch.exp(tensor_log_domain * log_k /  (2 ** sigmaPrecision))

    @staticmethod
    def lin2difflog(x: torch.Tensor, x_precision: int, output_precision: int, log_k: float) -> torch.Tensor:
        """Inverse function to difflog2lin()
        """
        return torch.round((torch.log(x / (2 ** x_precision)) / log_k * (2 ** output_precision)))

